/*
  Global Design System based on provided conference layout
  - Clean, modern, corporate
  - Strong black & white with vivid red accent
  - Space Grotesk for headings, IBM Plex Sans for body
*/

:root {
  /* Primary brand colors */
  --color-primary-red: #F03A32;
  --color-primary-black: #000000;

  /* Secondary neutrals */
  --color-secondary-gray-light: #C5C5C5;
  --color-secondary-gray: #808080;

  /* Accents */
  --color-accent-cyan: #00C4F0;
  --color-accent-green: #008C45;
  --color-accent-red-alt: #CD212A;

  /* Neutrals */
  --color-white: #FFFFFF;
  --color-neutral-50: #F5F5F5;
  --color-neutral-800: #333333;

  /* Semantic */
  --color-success: #17A550;
  --color-error: #E53935;
  --color-warning: #F9A825;
  --color-info: #0288D1;

  /* Typography */
  --font-heading: "Space Grotesk", Helvetica, sans-serif;
  --font-body: "IBM Plex Sans", Arial, sans-serif;
  --font-code: "Source Code Pro", monospace;

  --font-size-h1: 40px;
  --font-size-h2: 28px;
  --font-size-h3: 22px;
  --font-size-body: 16px;
  --font-size-small: 13px;

  --line-height-tight: 1.2;
  --line-height-normal: 1.5;
  --line-height-relaxed: 1.75;

  /* Spacing scale (8px base) */
  --space-0-5: 4px;
  --space-1: 8px;
  --space-2: 16px;
  --space-3: 24px;
  --space-4: 32px;
  --space-5: 48px;
  --space-6: 64px;

  /* Layout */
  --container-max-width: 1200px;
  --header-height-main: 72px;
  --top-bar-height: 32px;
  --border-radius-pill: 999px;
  --border-radius-sm: 3px;
}

/* Reset / base */

* {
  box-sizing: border-box;
}

html,
body {
  margin: 0;
  padding: 0;
}

body {
  font-family: var(--font-body);
  font-size: var(--font-size-body);
  line-height: var(--line-height-normal);
  color: var(--color-neutral-800);
  background-color: var(--color-white);
}

a {
  color: inherit;
  text-decoration: none;
}

a:hover,
a:focus {
  text-decoration: underline;
}

img {
  max-width: 100%;
  display: block;
}

.container {
  max-width: var(--container-max-width);
  margin: 0 auto;
  padding-left: var(--space-3);
  padding-right: var(--space-3);
}

.site-main {
  min-height: 60vh;
}

/* Top utility bar */

.top-bar {
  background-color: var(--color-neutral-50);
  height: var(--top-bar-height);
  display: flex;
  align-items: center;
  font-size: 13px;
}

.top-bar__inner {
  display: flex;
  align-items: center;
}

.top-bar__label {
  font-family: var(--font-body);
  font-weight: 500;
  color: var(--color-neutral-800);
}

/* Header */

.site-header {
  background-color: var(--color-white);
  border-bottom: 1px solid #e5e5e5;
}

.header-main {
  height: var(--header-height-main);
  display: flex;
  align-items: center;
}

.header-main__inner {
  display: flex;
  align-items: center;
  justify-content: space-between;
}

/* Brand */

.brand {
  display: flex;
  align-items: center;
  column-gap: var(--space-2);
}

.brand__logo {
  height: 48px;
  width: auto;
  object-fit: contain;
}

.brand__tagline {
  font-family: var(--font-heading);
  font-size: 13px;
  letter-spacing: 0.12em;
  text-transform: uppercase;
  color: var(--color-primary-red);
}

/* Primary navigation */

.primary-nav {
  flex: 1 1 auto;
  margin-left: var(--space-4);
}

.primary-nav__list {
  list-style: none;
  margin: 0;
  padding: 0;
  display: flex;
  flex-wrap: wrap;
  column-gap: var(--space-3);
  row-gap: var(--space-1);
  align-items: center;
}

.primary-nav__item {
  display: flex;
  align-items: center;
}

.primary-nav__link {
  font-family: var(--font-body);
  font-size: 14px;
  font-weight: 400;
  color: var(--color-neutral-800);
  padding: 6px 0;
  position: relative;
}

.primary-nav__link::after {
  content: "";
  position: absolute;
  left: 0;
  bottom: 0;
  width: 0;
  height: 2px;
  background-color: var(--color-primary-red);
  transition: width 0.18s ease-out;
}

.primary-nav__link:hover::after,
.primary-nav__link:focus::after,
.primary-nav__link--active::after {
  width: 100%;
}

/* CTA-style nav item (matches red pill button in design) */

.primary-nav__item--cta {
  margin-right: var(--space-2);
}

.primary-nav__link--cta {
  background-color: var(--color-primary-red);
  color: var(--color-white);
  padding: 10px 22px;
  border-radius: var(--border-radius-pill);
  font-weight: 500;
  text-decoration: none;
}

.primary-nav__link--cta::after {
  display: none;
}

.primary-nav__link--cta:hover,
.primary-nav__link--cta:focus {
  background-color: #d5332c;
  text-decoration: none;
}

/* Header meta (language indicator) */

.header-meta {
  margin-left: var(--space-3);
  display: flex;
  align-items: center;
}

.language-indicator {
  display: inline-flex;
  align-items: center;
  column-gap: 6px;
  font-size: 14px;
}

.language-indicator__flag {
  width: 18px;
  height: 12px;
  border-radius: 2px;
  background: linear-gradient(
    90deg,
    #008C45 0%,
    #008C45 33%,
    #FFFFFF 33%,
    #FFFFFF 66%,
    #CD212A 66%,
    #CD212A 100%
  );
  box-shadow: 0 0 0 1px rgba(0, 0, 0, 0.08);
}

.language-indicator__label {
  font-family: var(--font-body);
  color: var(--color-primary-red);
  font-weight: 500;
}

/* Footer */

.site-footer {
  background-color: var(--color-primary-black);
  color: var(--color-white);
  padding-top: var(--space-5);
}

.site-footer__main {
  display: flex;
  flex-wrap: wrap;
  justify-content: space-between;
  row-gap: var(--space-4);
}

.footer-brand {
  display: flex;
  align-items: center;
  column-gap: var(--space-2);
}

.footer-brand__mark {
  font-family: var(--font-heading);
  font-weight: 700;
  font-size: 26px;
  letter-spacing: 0.16em;
  text-transform: uppercase;
  color: var(--color-primary-red);
}

.footer-brand__title {
  font-family: var(--font-heading);
  font-size: 16px;
  font-weight: 500;
}

.footer-brand__subtitle {
  font-family: var(--font-body);
  font-size: 13px;
  color: var(--color-secondary-gray-light);
}

.footer-nav {
  display: flex;
  flex-wrap: wrap;
  column-gap: var(--space-5);
  row-gap: var(--space-4);
}

.footer-nav__column {
  min-width: 180px;
}

.footer-nav__heading {
  font-family: var(--font-heading);
  font-size: 14px;
  letter-spacing: 0.14em;
  text-transform: uppercase;
  margin: 0 0 var(--space-2);
}

.footer-nav__list {
  list-style: none;
  padding: 0;
  margin: 0;
}

.footer-nav__item + .footer-nav__item {
  margin-top: 6px;
}

.footer-nav__link {
  font-family: var(--font-body);
  font-size: 14px;
  color: var(--color-secondary-gray-light);
}

.footer-nav__link:hover,
.footer-nav__link:focus {
  color: var(--color-white);
  text-decoration: none;
}

.site-footer__bottom {
  border-top: 1px solid rgba(255, 255, 255, 0.16);
  margin-top: var(--space-4);
}

.site-footer__bottom-inner {
  padding-top: var(--space-2);
  padding-bottom: var(--space-2);
}

.site-footer__copyright {
  margin: 0;
  font-size: 13px;
  color: var(--color-secondary-gray-light);
}

/* Hero & card patterns (for page content, matching visual style) */

.hero {
  background-color: var(--color-primary-black);
  color: var(--color-white);
  padding-top: var(--space-6);
  padding-bottom: var(--space-6);
}

.hero__inner {
  display: flex;
  justify-content: space-between;
  align-items: center;
  gap: var(--space-4);
}

.hero__text {
  max-width: 720px;
}

.hero__eyebrow {
  font-family: var(--font-heading);
  font-size: 14px;
  letter-spacing: 0.18em;
  text-transform: uppercase;
  margin-bottom: var(--space-1);
}

.hero__title {
  font-family: var(--font-heading);
  font-size: var(--font-size-h1);
  line-height: var(--line-height-tight);
  text-transform: uppercase;
  margin: 0 0 var(--space-2);
}

.hero__subtitle {
  font-family: var(--font-body);
  font-size: 18px;
  line-height: var(--line-height-relaxed);
  max-width: 40rem;
}

/* Duration / metric card pattern */

.metric-card {
  width: 160px;
  height: 160px;
  border: 2px solid var(--color-white);
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  text-align: center;
}

.metric-card__value {
  font-family: var(--font-heading);
  font-size: 40px;
  font-weight: 500;
  margin-bottom: 6px;
}

.metric-card__label {
  font-family: var(--font-body);
  font-size: 14px;
  color: var(--color-secondary-gray-light);
}

/* Generic button pattern (for use inside page content) */

.btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  border-radius: var(--border-radius-pill);
  padding: 10px 22px;
  font-family: var(--font-body);
  font-size: 14px;
  font-weight: 500;
  border: 1px solid transparent;
  cursor: pointer;
  text-decoration: none;
}

.btn--primary {
  background-color: var(--color-primary-red);
  color: var(--color-white);
}

.btn--primary:hover,
.btn--primary:focus {
  background-color: #d5332c;
}

.btn--ghost {
  background-color: transparent;
  border-color: var(--color-primary-red);
  color: var(--color-primary-red);
}

.btn--ghost:hover,
.btn--ghost:focus {
  background-color: rgba(240, 58, 50, 0.06);
}

/* Forms (style baseline) */

.form-group {
  margin-bottom: var(--space-3);
}

.form-group label {
  display: block;
  margin-bottom: 6px;
  font-size: 14px;
}

.form-control {
  width: 100%;
  padding: 10px 12px;
  border-radius: 4px;
  border: 1px solid var(--color-secondary-gray-light);
  font-family: var(--font-body);
  font-size: 14px;
}

.form-control:focus {
  outline: none;
  border-color: var(--color-primary-red);
  box-shadow: 0 0 0 1px rgba(240, 58, 50, 0.4);
}

.form-helper {
  font-size: 12px;
  color: var(--color-secondary-gray);
  margin-top: 4px;
}

.form-helper--error {
  color: var(--color-error);
}

/* Responsive adjustments */

@media (max-width: 1024px) {
  .primary-nav__list {
    column-gap: var(--space-2);
  }

  .header-main__inner {
    align-items: flex-start;
  }

  .brand__tagline {
    display: none;
  }
}

@media (max-width: 768px) {
  .header-main {
    height: auto;
  }

  .header-main__inner {
    flex-direction: column;
    align-items: flex-start;
    gap: var(--space-2);
  }

  .primary-nav {
    margin-left: 0;
    width: 100%;
  }

  .primary-nav__list {
    flex-wrap: wrap;
    row-gap: var(--space-1);
  }

  .primary-nav__link {
    font-size: 13px;
  }

  .primary-nav__link--cta {
    padding: 8px 18px;
  }

  .site-footer__main {
    flex-direction: column;
    align-items: flex-start;
  }

  .hero__inner {
    flex-direction: column;
    align-items: flex-start;
  }
}
